// Author:  justin
// Description:  Token dispatching with FP8 block-scale dequantization
#include <cuda_runtime.h>
#include <cuda_fp8.h>
#include <cuda_fp16.h>
#include <cstdint>


// Convert FP8 E4M3 byte → float
__device__ __forceinline__ float fp8e4m3_to_float(__nv_fp8_storage_t val) {
    __half_raw hr = __nv_cvt_fp8_to_halfraw(val, __NV_E4M3);
    return __half2float(*reinterpret_cast<const __half*>(&hr));
}

// Dispatch kernel: scatter tokens into expert-grouped layout with FP8 dequantization
// Grid:  (T, TOP_K)
// Block: (256)
//
// Scale layout: [H/BLOCK_SCALE, T]  (column-major in the block dimension)
//   scale for token t, hidden dim h  =  hidden_states_scale[(h / BLOCK_SCALE) * T + t]
template<int H = 7168, int BLOCK_SCALE = 128>
__global__ void token_dispatch_kernel(
    const __nv_fp8_storage_t* __restrict__ hidden_states_fp8,  // [T, H]  FP8 E4M3
    const float* __restrict__ hidden_states_scale,             // [H/BLOCK_SCALE, T]  float32
    const int* __restrict__ token_expert_indices,              // [T, TOP_K]
    const int* __restrict__ token_expert_slots,                // [T, TOP_K]
    const int* __restrict__ expert_offsets,                    // [E_GLOBAL + 1]
    float* permuted_tokens,                                    // [total_assigned, H]
    int T, int TOP_K) {

    int token_idx = blockIdx.x;
    int k = blockIdx.y;
    int tid = threadIdx.x;

    if (token_idx >= T || k >= TOP_K) return;

    int expert_id = token_expert_indices[token_idx * TOP_K + k];
    if (expert_id < 0) return;

    int slot_in_expert = token_expert_slots[token_idx * TOP_K + k];
    int dest_row = expert_offsets[expert_id] + slot_in_expert;

    const __nv_fp8_storage_t* src_row = hidden_states_fp8 + token_idx * H;
    float* dst_row = permuted_tokens + dest_row * H;

    // Dequantize & scatter: read FP8 + block-scale → write float32
    // Process 4 FP8 values at a time for better memory throughput
    constexpr int VEC_SIZE = 4;
    int h_vec_end = (H / VEC_SIZE) * VEC_SIZE;

    for (int h = tid * VEC_SIZE; h < h_vec_end; h += blockDim.x * VEC_SIZE) {
        int block_idx = h / BLOCK_SCALE;
        float scale = hidden_states_scale[block_idx * T + token_idx];

        // Load 4 FP8 bytes at once
        uint32_t packed = *reinterpret_cast<const uint32_t*>(&src_row[h]);
        __nv_fp8_storage_t b0 = static_cast<__nv_fp8_storage_t>(packed & 0xFF);
        __nv_fp8_storage_t b1 = static_cast<__nv_fp8_storage_t>((packed >> 8) & 0xFF);
        __nv_fp8_storage_t b2 = static_cast<__nv_fp8_storage_t>((packed >> 16) & 0xFF);
        __nv_fp8_storage_t b3 = static_cast<__nv_fp8_storage_t>((packed >> 24) & 0xFF);

        // Check if all 4 values share the same scale block (128-byte aligned blocks)
        // For H=7168 and BLOCK_SCALE=128, blocks are exactly aligned with VEC_SIZE=4
        // so all 4 values within a single iteration share the same scale
        // (only need to check cross-block boundary at h % 128 >= 124, but VEC_SIZE=4 divides 128)

        float f0 = fp8e4m3_to_float(b0) * scale;
        float f1 = fp8e4m3_to_float(b1) * scale;
        float f2 = fp8e4m3_to_float(b2) * scale;
        float f3 = fp8e4m3_to_float(b3) * scale;

        // Vectorized store
        *reinterpret_cast<float4*>(&dst_row[h]) = make_float4(f0, f1, f2, f3);
    }

    // Handle remainder (H=7168 is divisible by 4, so this won't execute)
    for (int h = h_vec_end + tid; h < H; h += blockDim.x) {
        int block_idx = h / BLOCK_SCALE;
        float scale = hidden_states_scale[block_idx * T + token_idx];
        dst_row[h] = fp8e4m3_to_float(src_row[h]) * scale;
    }
}

void launch_token_dispatch(
    const __nv_fp8_storage_t* hidden_states_fp8,
    const float* hidden_states_scale,
    const int* token_expert_indices,
    const int* token_expert_slots,
    const int* expert_offsets,
    float* permuted_tokens,
    int T, int TOP_K, int H) {

    dim3 blocks(T, TOP_K);
    dim3 threads(256);

    token_dispatch_kernel<7168, 128><<<blocks, threads>>>(
        hidden_states_fp8,
        hidden_states_scale,
        token_expert_indices,
        token_expert_slots,
        expert_offsets,
        permuted_tokens,
        T, TOP_K
    );
}

// Author:  Eddie Tsai
// Description:  Expert MLP (GEMM1 -> SwiGLU -> GEMM2) with FP8 support
#include "kernel4_internal.cuh"

#include <algorithm>

using namespace moe_spec;

size_t k4_query_workspace(int seq_len,
                          int total_dispatched_tokens,
                          size_t cutlass_workspace_bytes) {
    size_t total = 0;
    total += kernel4_internal::align_up(kernel4_internal::gemm1_output_bytes(total_dispatched_tokens));
    total += kernel4_internal::align_up(kernel6_internal::gemm2_output_bytes(total_dispatched_tokens));
    total += kernel4_internal::align_up(kernel6_internal::output_accum_bytes(seq_len));
#if defined(K4_ENABLE_CUTLASS)
    cutlass_workspace_bytes = std::max(
        cutlass_workspace_bytes,
        kernel4_internal::cutlass_aux_bytes(total_dispatched_tokens));
#endif
    total += kernel4_internal::align_up(cutlass_workspace_bytes);
    return total;
}

Kernel4Workspace k4_bind_workspace(void* storage,
                                   size_t storage_bytes,
                                   int seq_len,
                                   int total_dispatched_tokens,
                                   size_t cutlass_workspace_bytes) {
    Kernel4Workspace workspace{};
    workspace.storage = storage;
    workspace.storage_bytes = storage_bytes;
#if defined(K4_ENABLE_CUTLASS)
    cutlass_workspace_bytes = std::max(
        cutlass_workspace_bytes,
        kernel4_internal::cutlass_aux_bytes(total_dispatched_tokens));
#endif
    workspace.cutlass_workspace_bytes = cutlass_workspace_bytes;
    if (!storage) {
        return workspace;
    }

    uintptr_t base = reinterpret_cast<uintptr_t>(storage);
    uintptr_t cursor = kernel4_internal::align_up(base);

    if (total_dispatched_tokens > 0) {
        workspace.gemm1_output = reinterpret_cast<__nv_bfloat16*>(cursor);
        cursor += kernel4_internal::align_up(
            kernel4_internal::gemm1_output_bytes(total_dispatched_tokens));

        workspace.gemm2_output = reinterpret_cast<float*>(cursor);
        cursor += kernel4_internal::align_up(
            kernel6_internal::gemm2_output_bytes(total_dispatched_tokens));
    }

    workspace.output_accum = reinterpret_cast<float*>(cursor);
    cursor += kernel4_internal::align_up(kernel6_internal::output_accum_bytes(seq_len));

    if (cutlass_workspace_bytes > 0) {
        workspace.cutlass_workspace = reinterpret_cast<void*>(cursor);
        cursor += kernel4_internal::align_up(cutlass_workspace_bytes);
    }

    if (cursor - base > storage_bytes) {
        Kernel4Workspace invalid{};
        invalid.storage = storage;
        invalid.storage_bytes = storage_bytes;
        return invalid;
    }

    return workspace;
}

bool k4_cutlass_available() {
#if defined(K4_ENABLE_CUTLASS)
    return kernel6_internal::current_device_is_sm86_or_better();
#else
    return false;
#endif
}

cudaError_t k4_launch_impl(const Kernel4Problem& p,
                           const Kernel4Workspace& workspace,
                           bool gemm1_only) {
    if (!p.expert_token_offsets || (!gemm1_only && !p.output)) {
        return cudaErrorInvalidValue;
    }

    int total_tokens = p.total_dispatched_tokens;
    if (total_tokens < 0) {
        int last = 0;
        CUDA_CHECK(cudaMemcpy(&last,
            p.expert_token_offsets + NUM_LOCAL_EXPERTS,
            sizeof(int), cudaMemcpyDeviceToHost));
        total_tokens = last;
    }

    if (total_tokens == 0) {
        if (!gemm1_only) {
            CUDA_CHECK(cudaMemsetAsync(
                p.output,
                0,
                (size_t)p.seq_len * HIDDEN_SIZE * sizeof(__nv_bfloat16),
                p.stream));
        }
        return cudaSuccess;
    }

    if (!p.hidden_states || !p.hidden_states_scale || !p.gemm1_weights ||
        !p.gemm1_weights_scale || !p.token_indices || 
        (!gemm1_only && (!p.gemm2_weights || !p.gemm2_weights_scale || !p.token_expert_weights))) {
        return cudaErrorInvalidValue;
    }

    const size_t required_workspace = k4_query_workspace(
        p.seq_len, total_tokens, workspace.cutlass_workspace_bytes);
    if (!workspace.storage || workspace.storage_bytes < required_workspace ||
        !workspace.gemm1_output || (!gemm1_only && (!workspace.gemm2_output || !workspace.output_accum))) {
        return cudaErrorInvalidValue;
    }

    if (p.backend == Kernel4Backend::Cutlass && !k4_cutlass_available()) {
        return cudaErrorNotSupported;
    }

#if defined(K4_ENABLE_CUTLASS)
    if ((p.backend == Kernel4Backend::Cutlass || p.backend == Kernel4Backend::Auto) &&
        k4_cutlass_available()) {
        return kernel4_internal::launch_cutlass_backend(p, workspace, total_tokens, gemm1_only);
    }
#endif

    if (p.backend == Kernel4Backend::Tiled) {
        return kernel4_internal::launch_tiled_backend(p, workspace, total_tokens, gemm1_only);
    }

    return kernel4_internal::launch_fallback_backend(p, workspace, total_tokens, gemm1_only);
}

cudaError_t k4_launch(const Kernel4Problem& p,
                      const Kernel4Workspace& workspace) {
    return k4_launch_impl(p, workspace, false);
}

cudaError_t k4_launch_gemm1(const Kernel4Problem& p,
                            const Kernel4Workspace& workspace) {
    return k4_launch_impl(p, workspace, true);
}

#pragma once

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cuda_fp8.h>
#include <cstdint>
#include <cstddef>

// ── Compile-time constants matching the spec ─────────────────────────────────
namespace moe_spec {
    constexpr int NUM_EXPERTS          = 256;
    constexpr int NUM_LOCAL_EXPERTS    = 32;
    constexpr int HIDDEN_SIZE          = 7168;
    constexpr int INTERMEDIATE_SIZE    = 2048;
    constexpr int GEMM1_OUT_SIZE       = 4096;   // = 2 * INTERMEDIATE_SIZE (W1||W3 fused)
    constexpr int NUM_HIDDEN_BLOCKS    = 56;     // 7168 / 128
    constexpr int NUM_GEMM1_OUT_BLOCKS = 32;     // 4096 / 128
    constexpr int NUM_INTER_BLOCKS     = 16;     // 2048 / 128
    constexpr int BLOCK_SIZE           = 128;    // universal quantization block size
    constexpr int TOP_K                = 8;      // DeepSeek-V3 top-8 routing
}

// Stored as raw bytes and decoded in the kernels.
using fp8_e4m3 = uint8_t;

enum class Kernel4Backend : int {
    Auto = 0,
    Fallback = 1,
    Tiled = 2,
    Cutlass = 3,
};

struct Kernel4Problem {
    const float*          routing_logits;       // [seq_len, NUM_EXPERTS]
    const __nv_bfloat16*  routing_bias;         // [NUM_EXPERTS]
    int                   seq_len;

    const fp8_e4m3*       hidden_states;        // [total_dispatched_tokens, HIDDEN_SIZE]
    const float*          hidden_states_scale;  // [NUM_HIDDEN_BLOCKS, seq_len]

    const fp8_e4m3*       gemm1_weights;        // [NUM_LOCAL_EXPERTS, GEMM1_OUT_SIZE, HIDDEN_SIZE]
    const float*          gemm1_weights_scale;  // [NUM_LOCAL_EXPERTS, NUM_GEMM1_OUT_BLOCKS, NUM_HIDDEN_BLOCKS]
    const fp8_e4m3*       gemm2_weights;        // [NUM_LOCAL_EXPERTS, HIDDEN_SIZE, INTERMEDIATE_SIZE]
    const float*          gemm2_weights_scale;  // [NUM_LOCAL_EXPERTS, NUM_HIDDEN_BLOCKS, NUM_INTER_BLOCKS]

    int                   local_expert_offset;    // this rank owns experts [offset, offset+32)
    float                 routed_scaling_factor;  // multiply final weighted sum
    const int*            expert_token_offsets;   // [NUM_LOCAL_EXPERTS + 1], device ptr
    const int*            host_expert_token_offsets = nullptr; // [NUM_LOCAL_EXPERTS + 1], optional host mirror
    int                   total_dispatched_tokens = -1;   // optional precomputed total, <0 means query from device
    const int*            token_indices;          // [total_dispatched_tokens], device ptr
    const int*            local_expert_ids;       // [total_dispatched_tokens], device ptr
    const float*          token_expert_weights;   // [total_dispatched_tokens], device ptr

    __nv_bfloat16*        output;                 // [seq_len, HIDDEN_SIZE]

    Kernel4Backend        backend;
    cudaStream_t          stream;
};

struct Kernel4Workspace {
    __nv_bfloat16* gemm1_output;     // [total_dispatched_tokens, INTERMEDIATE_SIZE]
    float*         gemm2_output;     // [total_dispatched_tokens, HIDDEN_SIZE]
    float*         output_accum;     // [seq_len, HIDDEN_SIZE]

    void*          storage;
    size_t         storage_bytes;

    void*          cutlass_workspace;
    size_t         cutlass_workspace_bytes;
};

// Query bytes for a single contiguous workspace allocation.
size_t k4_query_workspace(int seq_len,
                          int total_dispatched_tokens,
                          size_t cutlass_workspace_bytes = 0);

// Slice a caller-owned workspace allocation into typed buffers.
Kernel4Workspace k4_bind_workspace(void* storage,
                                   size_t storage_bytes,
                                   int seq_len,
                                   int total_dispatched_tokens,
                                   size_t cutlass_workspace_bytes = 0);

// True when this binary can execute the CUTLASS backend on the active device.
bool k4_cutlass_available();

cudaError_t k4_launch(const Kernel4Problem& problem,
                      const Kernel4Workspace& workspace);

cudaError_t k4_launch_gemm1(const Kernel4Problem& problem,
                            const Kernel4Workspace& workspace);

// Slow host reference used by tests.
void k4_reference_cpu(
    const float*   hidden_states_f32,      // [total_dispatched_tokens, HIDDEN_SIZE]
    const float*   hidden_states_scale,    // [NUM_HIDDEN_BLOCKS, seq_len]
    const int*     token_indices,          // [total_dispatched_tokens]
    const int*     expert_token_offsets,   // [NUM_LOCAL_EXPERTS + 1]
    const float*   gemm1_weights_f32,      // [NUM_LOCAL_EXPERTS, GEMM1_OUT_SIZE, HIDDEN_SIZE]
    const float*   gemm1_weights_scale,    // [NUM_LOCAL_EXPERTS, NUM_GEMM1_OUT_BLOCKS, NUM_HIDDEN_BLOCKS]
    const float*   gemm2_weights_f32,      // [NUM_LOCAL_EXPERTS, HIDDEN_SIZE, INTERMEDIATE_SIZE]
    const float*   gemm2_weights_scale,    // [NUM_LOCAL_EXPERTS, NUM_HIDDEN_BLOCKS, NUM_INTER_BLOCKS]
    const float*   token_expert_weights,   // [total_dispatched_tokens]
    float          routed_scaling_factor,
    int            seq_len,
    int            total_dispatched_tokens,
    float*         output_f32              // [seq_len, HIDDEN_SIZE]
);

#include "kernel4_internal.cuh"

namespace kernel4_internal {

cudaError_t launch_fallback_backend(const Kernel4Problem& p,
                                    const Kernel4Workspace& workspace,
                                    int total_tokens,
                                    bool gemm1_only) {
    dim3 block(256);
    if (total_tokens <= 14) {
        dim3 grouped_block(K4_GROUPED_SMALL_BN);
        dim3 grouped_grid((total_tokens + K4_GROUPED_SMALL_BT - 1) / K4_GROUPED_SMALL_BT,
                          INTERMEDIATE_SIZE / K4_GROUPED_SMALL_BN);
        fp8_gemm1_swiglu_grouped_small_kernel<<<grouped_grid, grouped_block, 0, p.stream>>>(
            p.hidden_states,
            p.hidden_states_scale,
            p.token_indices,
            p.local_expert_ids,
            p.gemm1_weights,
            p.gemm1_weights_scale,
            workspace.gemm1_output,
            total_tokens,
            p.seq_len
        );
    } else {
        dim3 gemm1_grid(total_tokens, (INTERMEDIATE_SIZE + block.x - 1) / block.x);
        fp8_gemm1_swiglu_reference_kernel<<<gemm1_grid, block, 0, p.stream>>>(
            p.hidden_states,
            p.hidden_states_scale,
            p.token_indices,
            p.local_expert_ids,
            p.gemm1_weights,
            p.gemm1_weights_scale,
            workspace.gemm1_output,
            total_tokens,
            p.seq_len
        );
    }
    CUDA_CHECK(cudaGetLastError());
    if (gemm1_only) {
        return cudaSuccess;
    }

    CUDA_CHECK(cudaMemsetAsync(
        workspace.output_accum,
        0,
        kernel6_internal::output_accum_bytes(p.seq_len),
        p.stream));

    kernel6_internal::Gemm2Problem shared_problem{};
    shared_problem.hidden_states = workspace.gemm1_output;
    shared_problem.gemm2_weights = p.gemm2_weights;
    shared_problem.gemm2_weights_scale = p.gemm2_weights_scale;
    shared_problem.expert_token_offsets = p.expert_token_offsets;
    shared_problem.host_expert_token_offsets = p.host_expert_token_offsets;
    shared_problem.token_indices = p.token_indices;
    shared_problem.local_expert_ids = p.local_expert_ids;
    shared_problem.token_expert_weights = p.token_expert_weights;
    shared_problem.routed_scaling_factor = p.routed_scaling_factor;
    shared_problem.seq_len = p.seq_len;
    shared_problem.stream = p.stream;
    shared_problem.output = p.output;

    kernel6_internal::Gemm2Workspace shared_workspace{};
    shared_workspace.gemm2_output = workspace.gemm2_output;
    shared_workspace.output_accum = workspace.output_accum;
    shared_workspace.cutlass_workspace = nullptr;
    shared_workspace.cutlass_workspace_bytes = 0;

    return kernel6_internal::launch_fallback_gemm2_combine(
        shared_problem, shared_workspace, total_tokens);
}

cudaError_t launch_tiled_backend(const Kernel4Problem& p,
                                 const Kernel4Workspace& workspace,
                                 int total_tokens,
                                 bool gemm1_only) {
    int local_host_offsets[NUM_LOCAL_EXPERTS + 1];
    const int* host_offsets = p.host_expert_token_offsets;
    if (!host_offsets) {
        CUDA_CHECK(cudaMemcpy(
            local_host_offsets,
            p.expert_token_offsets,
            sizeof(local_host_offsets),
            cudaMemcpyDeviceToHost));
        host_offsets = local_host_offsets;
    }

    dim3 block_gemm1(BN);
    dim3 block_micro(K4_MICRO_BN);
    dim3 block_small(K4_SMALL_BN);
    for (int expert = 0; expert < NUM_LOCAL_EXPERTS; ++expert) {
        int begin = host_offsets[expert];
        int end = host_offsets[expert + 1];
        int token_count = end - begin;
        if (token_count <= 0) {
            continue;
        }

        // hidden_states stays in original sequence order; token_indices_e
        // already remaps dispatched rows back to original tokens.
        const fp8_e4m3* act_e = p.hidden_states;
        const int* token_indices_e = p.token_indices + begin;
        const fp8_e4m3* w_e = p.gemm1_weights +
            (size_t)expert * GEMM1_OUT_SIZE * HIDDEN_SIZE;
        const float* ws_e = p.gemm1_weights_scale +
            (size_t)expert * NUM_GEMM1_OUT_BLOCKS * NUM_HIDDEN_BLOCKS;
        __nv_bfloat16* out_e = workspace.gemm1_output + (size_t)begin * INTERMEDIATE_SIZE;

        if (token_count <= 4) {
            dim3 grid_micro((token_count + K4_MICRO_BT - 1) / K4_MICRO_BT, NUM_INTER_BLOCKS);
            fp8_gemm1_swiglu_micro_kernel<<<grid_micro, block_micro, 0, p.stream>>>(
                act_e,
                p.hidden_states_scale,
                token_indices_e,
                token_count,
                w_e,
                ws_e,
                out_e,
                p.seq_len
            );
        } else if (token_count <= 16) {
            dim3 grid_small((token_count + K4_SMALL_BT - 1) / K4_SMALL_BT,
                            INTERMEDIATE_SIZE / K4_SMALL_BN);
            fp8_gemm1_swiglu_small_kernel<<<grid_small, block_small, 0, p.stream>>>(
                act_e,
                p.hidden_states_scale,
                token_indices_e,
                token_count,
                w_e,
                ws_e,
                out_e,
                p.seq_len
            );
        } else {
            dim3 grid_gemm1((token_count + BT - 1) / BT, NUM_INTER_BLOCKS);
            fp8_gemm1_swiglu_kernel<<<grid_gemm1, block_gemm1, 0, p.stream>>>(
                act_e,
                p.hidden_states_scale,
                token_indices_e,
                token_count,
                w_e,
                ws_e,
                out_e,
                p.seq_len
            );
        }
        CUDA_CHECK(cudaGetLastError());
    }

    if (gemm1_only) {
        return cudaSuccess;
    }

    CUDA_CHECK(cudaMemsetAsync(
        workspace.output_accum,
        0,
        kernel6_internal::output_accum_bytes(p.seq_len),
        p.stream));

    kernel6_internal::Gemm2Problem shared_problem{};
    shared_problem.hidden_states = workspace.gemm1_output;
    shared_problem.gemm2_weights = p.gemm2_weights;
    shared_problem.gemm2_weights_scale = p.gemm2_weights_scale;
    shared_problem.expert_token_offsets = p.expert_token_offsets;
    shared_problem.host_expert_token_offsets = p.host_expert_token_offsets;
    shared_problem.token_indices = p.token_indices;
    shared_problem.local_expert_ids = p.local_expert_ids;
    shared_problem.token_expert_weights = p.token_expert_weights;
    shared_problem.routed_scaling_factor = p.routed_scaling_factor;
    shared_problem.seq_len = p.seq_len;
    shared_problem.stream = p.stream;
    shared_problem.output = p.output;

    kernel6_internal::Gemm2Workspace shared_workspace{};
    shared_workspace.gemm2_output = workspace.gemm2_output;
    shared_workspace.output_accum = workspace.output_accum;
    shared_workspace.cutlass_workspace = nullptr;
    shared_workspace.cutlass_workspace_bytes = 0;

    return kernel6_internal::launch_fallback_gemm2_combine(
        shared_problem, shared_workspace, total_tokens);
}

}  // namespace kernel4_internal

#include "kernel4.cuh"

#include <cassert>
#include <cmath>
#include <cstring>
#include <vector>

using namespace moe_spec;

static float silu_f(float x) {
    return x / (1.f + expf(-x));
}

void k4_reference_cpu(
    const float* hidden_states_f32,
    const float* hidden_states_scale,
    const int*   token_indices,
    const int*   expert_token_offsets,
    const float* gemm1_weights_f32,
    const float* gemm1_weights_scale,
    const float* gemm2_weights_f32,
    const float* gemm2_weights_scale,
    const float* token_expert_weights,
    float        routed_scaling_factor,
    int          seq_len,
    int          total_dispatched_tokens,
    float*       output_f32)
{
    memset(output_f32, 0, (size_t)seq_len * HIDDEN_SIZE * sizeof(float));

    for (int tok = 0; tok < total_dispatched_tokens; ++tok) {
        int expert_id = 0;
        for (int e = 0; e < NUM_LOCAL_EXPERTS; ++e) {
            if (tok >= expert_token_offsets[e] && tok < expert_token_offsets[e + 1]) {
                expert_id = e;
                break;
            }
        }

        int orig_tok = token_indices[tok];
        assert(orig_tok >= 0 && orig_tok < seq_len);

        const float* W1 = gemm1_weights_f32 + (size_t)expert_id * GEMM1_OUT_SIZE * HIDDEN_SIZE;
        const float* W1s = gemm1_weights_scale + (size_t)expert_id * NUM_GEMM1_OUT_BLOCKS * NUM_HIDDEN_BLOCKS;
        const float* W2 = gemm2_weights_f32 + (size_t)expert_id * HIDDEN_SIZE * INTERMEDIATE_SIZE;
        const float* W2s = gemm2_weights_scale + (size_t)expert_id * NUM_HIDDEN_BLOCKS * NUM_INTER_BLOCKS;
        float rw = token_expert_weights[tok] * routed_scaling_factor;

        std::vector<float> inter(INTERMEDIATE_SIZE, 0.f);
        for (int out_col = 0; out_col < INTERMEDIATE_SIZE; ++out_col) {
            float acc_up = 0.f;
            float acc_gate = 0.f;
            int bn_up = out_col / BLOCK_SIZE;
            int bn_gate = (INTERMEDIATE_SIZE + out_col) / BLOCK_SIZE;
            for (int bk = 0; bk < NUM_HIDDEN_BLOCKS; ++bk) {
                float a_scale = hidden_states_scale[bk * seq_len + orig_tok];
                float ws_up = W1s[bn_up * NUM_HIDDEN_BLOCKS + bk];
                float ws_gate = W1s[bn_gate * NUM_HIDDEN_BLOCKS + bk];

                float dot_up = 0.f;
                float dot_gate = 0.f;
                int k_base = bk * BLOCK_SIZE;
                for (int k = 0; k < BLOCK_SIZE; ++k) {
                    float a = hidden_states_f32[tok * HIDDEN_SIZE + k_base + k] * a_scale;
                    dot_up += a * W1[out_col * HIDDEN_SIZE + k_base + k] * ws_up;
                    dot_gate += a * W1[(INTERMEDIATE_SIZE + out_col) * HIDDEN_SIZE + k_base + k] * ws_gate;
                }

                acc_up += dot_up;
                acc_gate += dot_gate;
            }

            inter[out_col] = acc_gate * silu_f(acc_up);
        }

        for (int out_h = 0; out_h < HIDDEN_SIZE; ++out_h) {
            float acc = 0.f;
            int hb = out_h / BLOCK_SIZE;
            for (int ib = 0; ib < NUM_INTER_BLOCKS; ++ib) {
                float tile_scale = W2s[hb * NUM_INTER_BLOCKS + ib];
                int k_base = ib * BLOCK_SIZE;
                float dot = 0.f;
                for (int k = 0; k < BLOCK_SIZE; ++k) {
                    float a = inter[k_base + k];
                    float w = W2[out_h * INTERMEDIATE_SIZE + k_base + k];
                    dot += a * w;
                }
                acc += dot * tile_scale;
            }

            output_f32[orig_tok * HIDDEN_SIZE + out_h] += acc * rw;
        }
    }
}

#include "kernel4_internal.cuh"

namespace kernel4_internal {

__global__ void fp8_gemm1_swiglu_kernel(
    const fp8_e4m3* __restrict__ act,
    const float*    __restrict__ act_scale,
    const int*      __restrict__ token_indices,
    int             T_e,
    const fp8_e4m3* __restrict__ W,
    const float*    __restrict__ W_scale,
    __nv_bfloat16*  __restrict__ out,
    int             seq_len)
{
    int tile_t  = blockIdx.x * BT;
    int tile_bn = blockIdx.y;
    int tid = threadIdx.x;

    __shared__ float A_smem[BT][BK];

    int local_col = tid;
    int up_col = tile_bn * BN + local_col;
    int gate_col = INTERMEDIATE_SIZE + tile_bn * BN + local_col;

    float acc_up[BT] = {};
    float acc_gate[BT] = {};

    for (int bk = 0; bk < NUM_HIDDEN_BLOCKS; ++bk) {
        int k_base = bk * BK;

        for (int t = 0; t < BT; ++t) {
            int tok = tile_t + t;
            if (tok < T_e && local_col < BK) {
                int orig_tok = load_cached(token_indices + tok);
                A_smem[t][local_col] = fp8_to_float(act[(size_t)orig_tok * HIDDEN_SIZE + k_base + local_col]);
            } else if (local_col < BK) {
                A_smem[t][local_col] = 0.f;
            }
        }


        __syncthreads();

        float w_scale_up = (up_col < GEMM1_OUT_SIZE)
            ? load_cached(W_scale + tile_bn * NUM_HIDDEN_BLOCKS + bk)
            : 0.f;
        float w_scale_gate = (gate_col < GEMM1_OUT_SIZE)
            ? load_cached(W_scale + (INTERMEDIATE_SIZE / BN + tile_bn) * NUM_HIDDEN_BLOCKS + bk)
            : 0.f;

        for (int t = 0; t < BT; ++t) {
            int tok = tile_t + t;
            int orig_tok = (tok < T_e) ? load_cached(token_indices + tok) : 0;
            float a_scale = (tok < T_e) ? load_cached(act_scale + bk * seq_len + orig_tok) : 0.f;

            float dot_up = 0.f;
            float dot_gate = 0.f;
            for (int k = 0; k < BK; ++k) {
                float w_up = (up_col < GEMM1_OUT_SIZE)
                    ? fp8_to_float(W[up_col * HIDDEN_SIZE + k_base + k])
                    : 0.f;
                float w_gate = (gate_col < GEMM1_OUT_SIZE)
                    ? fp8_to_float(W[gate_col * HIDDEN_SIZE + k_base + k])
                    : 0.f;
                dot_up += A_smem[t][k] * w_up;
                dot_gate += A_smem[t][k] * w_gate;
            }
            acc_up[t] += dot_up * a_scale * w_scale_up;
            acc_gate[t] += dot_gate * a_scale * w_scale_gate;
        }

        __syncthreads();
    }

    for (int t = 0; t < BT; ++t) {
        int tok = tile_t + t;
        if (tok >= T_e) break;

        float up = acc_up[t];
        float gate = acc_gate[t];
        float silu_up = up * (1.f / (1.f + expf(-up)));
        float result = gate * silu_up;

        out[tok * INTERMEDIATE_SIZE + up_col] = __float2bfloat16(result);
    }
}

__global__ void fp8_gemm1_swiglu_reference_kernel(
    const fp8_e4m3* __restrict__ act,
    const float*    __restrict__ act_scale,
    const int*      __restrict__ token_indices,
    const int*      __restrict__ local_expert_ids,
    const fp8_e4m3* __restrict__ W,
    const float*    __restrict__ W_scale,
    __nv_bfloat16*  __restrict__ out,
    int             total_tokens,
    int             seq_len)
{
    int tok = blockIdx.x;
    int out_col = threadIdx.x + blockIdx.y * blockDim.x;
    int row = threadIdx.x;

    if (tok >= total_tokens || out_col >= INTERMEDIATE_SIZE) return;

    int expert_id = load_cached(local_expert_ids + tok);

    int orig_tok = load_cached(token_indices + tok);
    const fp8_e4m3* W_e = W + (size_t)expert_id * GEMM1_OUT_SIZE * HIDDEN_SIZE;
    const float* Ws_e = W_scale + (size_t)expert_id * NUM_GEMM1_OUT_BLOCKS * NUM_HIDDEN_BLOCKS;

    float acc_up = 0.f;
    float acc_gate = 0.f;
    int bn_up = out_col / BLOCK_SIZE;
    int bn_gate = (INTERMEDIATE_SIZE + out_col) / BLOCK_SIZE;

    __shared__ uint8_t W_smem[256][BK];

    for (int bk = 0; bk < NUM_HIDDEN_BLOCKS; ++bk) {
        float a_scale = load_cached(act_scale + bk * seq_len + orig_tok);
        float ws_up = load_cached(Ws_e + bn_up * NUM_HIDDEN_BLOCKS + bk);
        float ws_gate = load_cached(Ws_e + bn_gate * NUM_HIDDEN_BLOCKS + bk);

        int k_base = bk * BLOCK_SIZE;
        for (int k = 0; k < BLOCK_SIZE; ++k) {
            W_smem[row][k] = load_cached(W_e + out_col * HIDDEN_SIZE + k_base + k);
        }
        __syncthreads();

        for (int k = 0; k < BLOCK_SIZE; ++k) {
            float a = fp8_to_float(act[(size_t)orig_tok * HIDDEN_SIZE + k_base + k]) * a_scale;
            acc_up += a * fp8_to_float(W_smem[row][k]) * ws_up;
        }


        for (int k = 0; k < BLOCK_SIZE; ++k) {
            W_smem[row][k] = load_cached(W_e + (INTERMEDIATE_SIZE + out_col) * HIDDEN_SIZE + k_base + k);
        }
        __syncthreads();

        for (int k = 0; k < BLOCK_SIZE; ++k) {
            float a = fp8_to_float(act[(size_t)orig_tok * HIDDEN_SIZE + k_base + k]) * a_scale;
            acc_gate += a * fp8_to_float(W_smem[row][k]) * ws_gate;
        }


        __syncthreads();
    }

    float silu_gate = acc_gate * (1.f / (1.f + expf(-acc_gate)));
    float result = acc_up * silu_gate;
    out[tok * INTERMEDIATE_SIZE + out_col] = __float2bfloat16(result);
}

__global__ void fp8_gemm1_swiglu_micro_kernel(
    const fp8_e4m3* __restrict__ act,
    const float*    __restrict__ act_scale,
    const int*      __restrict__ token_indices,
    int             T_e,
    const fp8_e4m3* __restrict__ W,
    const float*    __restrict__ W_scale,
    __nv_bfloat16*  __restrict__ out,
