struct WorkspaceCache {
    void* ptr = nullptr;
    size_t bytes = 0;

    ~WorkspaceCache() {
        if (ptr) {
            cudaFree(ptr);
        }
    }

    void* reserve(size_t requested_bytes) {
        if (requested_bytes == 0) {
            return nullptr;
        }
        if (bytes >= requested_bytes && ptr) {
            return ptr;
        }
        if (ptr) {
            cudaFree(ptr);
            ptr = nullptr;
            bytes = 0;
        }
        if (cudaMalloc(&ptr, requested_bytes) != cudaSuccess) {
            ptr = nullptr;
            bytes = 0;
            return nullptr;
        }
        bytes = requested_bytes;
        return ptr;
    }
};

