#include <cuda_runtime.h>

template<int E_LOCAL, int TOP_K>
__global__ void moe_reindex_kernel(
    const int* __restrict__ token_expert_indices,
    const float* __restrict__ token_expert_weights,
    const int* __restrict__ token_expert_slots,
    const int* __restrict__ expert_token_offsets,
    int* __restrict__ token_indices,
    int* __restrict__ local_expert_ids,
    float* __restrict__ merged_token_weights,
    int seq_len,
    int local_expert_offset) {

    int linear = blockIdx.x * blockDim.x + threadIdx.x;
    int total = seq_len * TOP_K;
    if (linear >= total) return;

    int token = linear / TOP_K;
    int global_expert = token_expert_indices[linear];
    int local_expert = global_expert - local_expert_offset;

    if (local_expert < 0 || local_expert >= E_LOCAL) return;

    int slot = token_expert_slots[linear];
    int dest = expert_token_offsets[local_expert] + slot;
    token_indices[dest] = token;
    local_expert_ids[dest] = local_expert;
    merged_token_weights[dest] = token_expert_weights[linear];
}

void launch_moe_reindex(
    const int* token_expert_indices,
    const float* token_expert_weights,
    const int* token_expert_slots,
    const int* expert_token_offsets,
    int* token_indices,
    int* local_expert_ids,
    float* merged_token_weights,
    int seq_len,
    int local_expert_offset,
    cudaStream_t stream = 0) {

    constexpr int E_LOCAL = 32;
    constexpr int TOP_K = 8;
    int total = seq_len * TOP_K;
    int threads = 256;
    int blocks = (total + threads - 1) / threads;

    moe_reindex_kernel<E_LOCAL, TOP_K><<<blocks, threads, 0, stream>>>(
        token_expert_indices,
        token_expert_weights,
        token_expert_slots,
        expert_token_offsets,
        token_indices,
        local_expert_ids,
        merged_token_weights,
        seq_len,
        local_expert_offset);
}

// Author:  wei-min chen
// Description:  DeepSeek-V3 "No-aux" routing logic (Sigmoid + Groups + Top-K)
#include <cub/cub.cuh>
#include <cuda_bf16.h>
#include "include/utils.cuh"

struct rankItem {
    float score;
    int idx;

    __device__ __forceinline__ bool operator>(const rankItem& other) const {
        if (score > other.score) return true;
        if (score < other.score) return false;
        return idx < other.idx;
    }
};

struct GreaterRankItem {
    __device__ __forceinline__ bool operator()(const rankItem& a, const rankItem& b) const {
        return (a.score > b.score) || (a.score == b.score && a.idx < b.idx);
    }
};

template<int E_GLOBAL, int E_LOCAL, int TOP_K>
__global__ void router(
    const float* __restrict__ routing_logits, // [T, E_global]
    const __nv_bfloat16* __restrict__ routing_bias,   // [E_global]
    int* expert_token_counts,                 // [E_global]
    int* token_expert_indices,                // [T, TOP_K]
    float* token_expert_weights,              // [T, TOP_K]
    int* token_expert_slots,                  // [T, TOP_K]
    int T, int local_expert_offset, float routed_scaling_factor) {

    int token = blockIdx.x;
    if (token >= T) return;

    constexpr int N_GROUP = 8;
    constexpr int TOPK_GROUP = 4;
    constexpr int GROUP_SIZE = E_GLOBAL / N_GROUP; // 32

    int tid = threadIdx.x;
    int group_id = tid / GROUP_SIZE;
    int lane_id = tid % GROUP_SIZE;

    // --- Shared memory allocations ---
    typedef cub::WarpMergeSort<rankItem, 1, 32> WarpSort32;
    __shared__ typename WarpSort32::TempStorage warp_sort_temp[N_GROUP];

    typedef cub::WarpMergeSort<rankItem, 2, 32> WarpSort64;
    __shared__ typename WarpSort64::TempStorage final_sort_temp;

    __shared__ float s_group_scores[N_GROUP];
    __shared__ bool group_mask[N_GROUP];
    __shared__ rankItem shared_candidates[64];
    __shared__ int final_indices[8];


    // Initialization
    if (tid < 8) final_indices[tid] = -1;
    __syncthreads();

    // 1. Warp Sort for Group Top-2
    float logit = routing_logits[token * E_GLOBAL + tid];
    float s_wb = sigmoid(logit + __bfloat162float(routing_bias[tid]));

    rankItem item_arr[1];
    item_arr[0].score = s_wb;
    item_arr[0].idx = tid;

    WarpSort32(warp_sort_temp[group_id]).Sort(item_arr, GreaterRankItem());

    float group_top1 = __shfl_sync(0xffffffff, item_arr[0].score, 0);
    float group_top2 = __shfl_sync(0xffffffff, item_arr[0].score, 1);

    if (lane_id == 0) {
        s_group_scores[group_id] = group_top1 + group_top2;
    }
    __syncthreads();

    // 2. Select Top-4 groups
    if (tid < N_GROUP) {
        float my_score = s_group_scores[tid];
        int rank = 0;
        #pragma unroll
        for (int i = 0; i < N_GROUP; ++i) {
            if (s_group_scores[i] > my_score || (s_group_scores[i] == my_score && i < tid)) rank++;
        }
        group_mask[tid] = (rank < TOPK_GROUP);
    }
    __syncthreads();

    // 3. Select Global Top-K from 64 candidates
    item_arr[0].score = (group_mask[group_id]) ? s_wb : -1e20f;
    item_arr[0].idx = tid;

    WarpSort32(warp_sort_temp[group_id]).Sort(item_arr, GreaterRankItem());

    if (lane_id < 8) {
        shared_candidates[group_id * 8 + lane_id] = item_arr[0];
    }
    __syncthreads();

    // Warp 0 does the final reduction
    if (tid < 32) {
        rankItem candidates[2];
        candidates[0] = shared_candidates[tid];
        candidates[1] = shared_candidates[tid + 32];

        WarpSort64(final_sort_temp).Sort(candidates, GreaterRankItem());

        // threads 0-3 have top-8
        float winner_s_arr[2] = {0.0f, 0.0f};
        if (tid < 4) {
            #pragma unroll
            for (int i = 0; i < 2; ++i) {
                if (candidates[i].score > -1e10f) {
                    winner_s_arr[i] = sigmoid(routing_logits[token * E_GLOBAL + candidates[i].idx]);
                }
            }
        }

        float partial_sum = winner_s_arr[0] + winner_s_arr[1];
        #pragma unroll
        for (int offset = 16; offset > 0; offset >>= 1) {
            partial_sum += __shfl_xor_sync(0xffffffff, partial_sum, offset);
        }

        float total_sigmoid_sum = partial_sum + 1e-20f;

        if (tid < 4) {
            #pragma unroll
            for (int i = 0; i < 2; ++i) {
                if (candidates[i].score > -1e10f) {
                    int pos = tid * 2 + i;
                    float weight = (winner_s_arr[i] / total_sigmoid_sum) * routed_scaling_factor;
                    token_expert_indices[token * TOP_K + pos] = candidates[i].idx;
                    token_expert_weights[token * TOP_K + pos] = weight;
                    final_indices[pos] = candidates[i].idx;
                }
            }
        }
    }
    __syncthreads();

    // 4. Expert Counting & Slot Assignment via atomicAdd
    if (tid < TOP_K && final_indices[tid] != -1) {
        int expert_id = final_indices[tid];
        int slot = atomicAdd(&expert_token_counts[expert_id], 1);
        token_expert_slots[token * TOP_K + tid] = slot;
    }
}

// Author:  Jie-Kai Chang
// Description:  Expert offset calculation via Exclusive Prefix Sum (Scan)

// Kernel 2: Prefix Sum (Scan) using CUB
// Logic: Converts expert token counts into global offsets (pointers)
//        in the dispatch buffer via exclusive prefix sum.
//
// Input:  expert_token_counts[E]  — number of tokens routed to each expert
// Output: expert_offsets[E+1]     — exclusive prefix sum
//         expert_offsets[e] = sum of counts for experts 0..e-1
//         expert_offsets[E] = total number of routed tokens
//
// Uses cub::DeviceScan::ExclusiveSum which is a highly optimized,
// work-efficient parallel scan implementation that automatically
// selects the best algorithm for the given hardware and problem size.

#include <cub/cub.cuh>
#include <cuda_runtime.h>

// ============================================================================
// Core Scan Implementation
// ============================================================================

/// @brief Performs an exclusive prefix sum (scan) on device memory using CUB.
///
/// Given an input array [c0, c1, c2, ..., cN-1], produces:
///   output[0] = 0
///   output[1] = c0
///   output[2] = c0 + c1
///   ...
///   output[N-1] = c0 + c1 + ... + cN-2
///
/// This is used to convert per-expert token counts into global offsets
/// into the dispatch buffer. The last element output[E] gives the total
/// number of tokens dispatched, which equals the dispatch buffer size.
///
/// @param d_input   Device pointer to input array (expert token counts)
/// @param d_output  Device pointer to output array (expert offsets)
/// @param num_items Number of elements to scan
/// @param stream    CUDA stream for async execution (default: 0)
void exclusive_scan_cub(int* d_input, int* d_output, int num_items,
                        cudaStream_t stream = 0) {
    // Phase 1: Query temporary storage requirements
    // CUB uses a two-phase pattern: first call with nullptr to get size,
    // then allocate and call again to execute.
    void* d_temp_storage = nullptr;
    size_t temp_storage_bytes = 0;
    cub::DeviceScan::ExclusiveSum(
        d_temp_storage, temp_storage_bytes,
        d_input, d_output, num_items, stream);

    // Phase 2: Allocate temporary storage
    cudaMalloc(&d_temp_storage, temp_storage_bytes);

    // Phase 3: Execute the exclusive prefix sum
    cub::DeviceScan::ExclusiveSum(
        d_temp_storage, temp_storage_bytes,
        d_input, d_output, num_items, stream);

    // Sync before free!
    cudaStreamSynchronize(stream);

    // Cleanup temporary storage
    cudaFree(d_temp_storage);
}


// ============================================================================
// Persistent-buffer variant (avoids repeated malloc/free in hot path)
// ============================================================================

/// @brief Scan variant that reuses pre-allocated temporary storage.
///
/// For production use where the scan is called repeatedly (e.g., every
/// inference step), pre-allocating the temporary buffer avoids the
/// overhead of cudaMalloc/cudaFree on each call.
///
/// Usage:
///   1. Call get_scan_temp_storage_bytes() once to get required size
///   2. Allocate buffer once with cudaMalloc
///   3. Call exclusive_scan_cub_persistent() on each iteration
///   4. Free buffer on shutdown
///
/// @param d_temp_storage  Pre-allocated temporary storage
/// @param temp_storage_bytes  Size of temporary storage in bytes
/// @param d_input   Device pointer to input array
/// @param d_output  Device pointer to output array
/// @param num_items Number of elements to scan
/// @param stream    CUDA stream (default: 0)
void exclusive_scan_cub_persistent(void* d_temp_storage,
                                   size_t temp_storage_bytes,
                                   int* d_input, int* d_output,
                                   int num_items,
                                   cudaStream_t stream = 0) {
    cub::DeviceScan::ExclusiveSum(
        d_temp_storage, temp_storage_bytes,
        d_input, d_output, num_items, stream);
}

/// @brief Returns the temporary storage size required by CUB for a given
///        scan problem size. Use this to pre-allocate a persistent buffer.
///
/// @param num_items Number of elements to scan
/// @return          Required temporary storage size in bytes
size_t get_scan_temp_storage_bytes(int num_items) {
    void* d_temp = nullptr;
    size_t bytes = 0;
    cub::DeviceScan::ExclusiveSum(d_temp, bytes,
                                  (int*)nullptr, (int*)nullptr, num_items);
    return bytes;
}
